SELECT subject_id
FROM subjects
WHERE strftime('%Y', date('now')) - strftime('%Y', date_of_birth) < 18;

SELECT subject_id, health_status
FROM subjects
WHERE health_status = (SELECT MAX(health_status) FROM subjects);

SELECT subject_id 
FROM sensor_data 
WHERE sampling_rate = (SELECT MAX(sampling_rate) FROM sensor_data);

SELECT AVG(accel_x) AS AvgAccelX
FROM sensor_data
WHERE activity_type = 'Falling on the right' AND subject_id = 'subject1';

SELECT sensor_type, activity_type, COUNT(data_id) AS total_data_points
FROM sensor_data
GROUP BY sensor_type, activity_type;

SELECT sensor_type, COUNT(data_id) AS count
FROM sensor_data
GROUP BY sensor_type;

SELECT *
FROM subjects
WHERE subject_id IN (SELECT subject_id FROM sensor_data);

SELECT s.first_name || ' ' || s.last_name AS subject_name, sd.activity_type, sd.sensor_type
FROM sensor_data sd
JOIN subjects s ON sd.subject_id = s.subject_id;

SELECT subject_id, activity_type
FROM sensor_data
WHERE accel_x > 0.5 AND accel_y > 0.5 AND accel_z > 0.5;

SELECT DISTINCT subject_id 
FROM sensor_data 
WHERE sampling_rate > 100;
